// Extract distinct Storage Location names and Bin Location combines from the
// imported excel rows so the downstream search-nodes can resolve them to IDs.
const excelData = JSON.parse({{workflowparams:excelData}});

const storageNames = [];
const binCombines = [];
const uomNames = [];

Object.keys(excelData).forEach((k) => {
  // numeric-keyed entries are the data rows; skip name/size/type meta keys
  if (/^\d+$/.test(k)) {
    const row = excelData[k] || {};
    const s = row["Storage Location"] ? String(row["Storage Location"]).trim() : "";
    const b = row["Bin Location"] ? String(row["Bin Location"]).trim() : "";
    // Optional "UOM" column: when present the Quantity is expressed in that UOM
    // and the build node converts it to the GR line's UOM.
    const u = row["UOM"] ? String(row["UOM"]).trim() : "";
    if (s && storageNames.indexOf(s) === -1) storageNames.push(s);
    if (b && binCombines.indexOf(b) === -1) binCombines.push(b);
    if (u && uomNames.indexOf(u) === -1) uomNames.push(u);
  }
});

// Never feed an empty array into an `in` filter; use a sentinel that is
// extremely unlikely to match a real name so the build node can still report
// the missing-location errors cleanly.
if (storageNames.length === 0) storageNames.push("0");
if (binCombines.length === 0) binCombines.push("0");
if (uomNames.length === 0) uomNames.push("0");

return { storageNames: storageNames, binCombines: binCombines, uomNames: uomNames };

// Validate the imported excel rows and build split_dialog.table_split.
// All validations accumulate into `errors`; any error -> code 400.
const excelData = JSON.parse({{workflowparams:excelData}});
const item = {{node:get_node_item.data.data}};
const storageList = {{node:search_node_storage.data.data}} || [];
const binList = {{node:search_node_bin.data.data}} || [];
const uomList = {{node:search_node_uom.data.data}} || [];
const binDefaultList = {{node:search_node_bin_default.data.data}} || [];
const itemUom = {{workflowparams:item_uom}} || "";
const orderedQty = parseFloat({{workflowparams:ordered_qty}}) || 0;
const initialReceivedQty = parseFloat({{workflowparams:initial_received_qty}}) || 0;
const orderedQtyUom = {{workflowparams:ordered_qty_uom}} || "";

// --- UOM conversion setup -------------------------------------------------
// The split dialog stores received_qty in the GR line's UOM (itemUom). When a
// row carries a "UOM" column we convert its Quantity into itemUom using the
// item's conversion table, where base_qty = base units per 1 unit of that UOM:
//   qty_in_line_uom = excelQty * base_qty[excelUom] / base_qty[itemUom]
const uomConv = Array.isArray(item.table_uom_conversion)
  ? item.table_uom_conversion
  : [];
// base_qty factor for a given uom id (base UOM = 1 when it has no explicit row)
const baseQtyFor = (uomId) => {
  const row = uomConv.find((c) => String(c.alt_uom_id) === String(uomId));
  if (row && row.base_qty) return parseFloat(row.base_qty);
  if (String(uomId) === String(item.based_uom)) return 1;
  return null; // not a valid UOM for this item
};
const itemUomFactor = baseQtyFor(itemUom) || 1;

// Collect numeric-keyed rows only (skip name/size/type meta keys), in order.
const rows = [];
Object.keys(excelData).forEach((k) => {
  if (/^\d+$/.test(k)) {
    rows.push({ __idx: parseInt(k, 10), data: excelData[k] });
  }
});
rows.sort((a, b) => a.__idx - b.__idx);

const errors = [];
const autoBatchWarnRows = [];

// Batch mode is derived from the Item master, not the excel.
const isBatchItem = item.item_batch_management === 1;
const isAutoBatch =
  isBatchItem && item.batch_number_genaration === "According To System Settings";

// Parse a date to YYYY-MM-DD. A 4-digit year is always required. Accepts:
//   DD-MM-YYYY / D-M-YYYY, DD/MM/YYYY        (numeric, DAY-first)
//   YYYY-MM-DD / YYYY/MM/DD                  (ISO, year-first)
//   "1 Jan 2026" / "1 January 2026" / "1-Jan-2026"  (day month-name year)
// Returns: null (empty), "YYYY-MM-DD" (valid), or {error:true,raw} (bad/impossible).
// Calendar validity is checked manually (no Date dependency in the sandbox).
const MONTHS = {
  jan: 1, january: 1, feb: 2, february: 2, mar: 3, march: 3, apr: 4, april: 4,
  may: 5, jun: 6, june: 6, jul: 7, july: 7, aug: 8, august: 8,
  sep: 9, sept: 9, september: 9, oct: 10, october: 10, nov: 11, november: 11,
  dec: 12, december: 12,
};
const convertDate = (val) => {
  if (val === undefined || val === null || String(val).trim() === "") return null;
  const s = String(val).trim();
  let dNum, mNum, yNum;
  let m;
  if ((m = s.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})$/))) {
    // ISO year-first
    yNum = parseInt(m[1], 10); mNum = parseInt(m[2], 10); dNum = parseInt(m[3], 10);
  } else if ((m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/))) {
    // numeric day-first
    dNum = parseInt(m[1], 10); mNum = parseInt(m[2], 10); yNum = parseInt(m[3], 10);
  } else if ((m = s.match(/^(\d{1,2})[\s\-]+([A-Za-z]+)[\s\-]+(\d{4})$/))) {
    // day month-name year
    dNum = parseInt(m[1], 10); yNum = parseInt(m[3], 10);
    mNum = MONTHS[m[2].toLowerCase()];
    if (!mNum) return { error: true, raw: s };
  } else {
    return { error: true, raw: s };
  }
  const isLeap = yNum % 4 === 0 && (yNum % 100 !== 0 || yNum % 400 === 0);
  const daysInMonth = [31, isLeap ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
  if (mNum < 1 || mNum > 12 || dNum < 1 || dNum > daysInMonth[mNum - 1]) {
    return { error: true, raw: s };
  }
  const dd = String(dNum).padStart(2, "0");
  const mm = String(mNum).padStart(2, "0");
  return yNum + "-" + mm + "-" + dd;
};

const str = (v) => (v === undefined || v === null ? "" : String(v));

const tableSplit = [];
let totalReceived = 0;

rows.forEach((r, i) => {
  const row = r.data || {};
  const lineNo = i + 1;

  // 1a. Item match (item_id is already known; confirm the excel refers to it)
  const itemCode = str(row["Item Code"]).trim();
  if (itemCode !== str(item.material_code).trim()) {
    errors.push(
      "Row " + lineNo + ': Item Code "' + itemCode +
        '" does not match the item on this line (' + str(item.material_code) + ").");
  }

  // 3a. Quantity (+ optional UOM conversion to the GR line's UOM)
  const rawQty = parseFloat(row["Quantity"]);
  let lineQty = NaN;
  if (isNaN(rawQty) || rawQty <= 0) {
    errors.push("Row " + lineNo + ": Quantity must be greater than 0.");
  } else {
    const excelUomName = str(row["UOM"]).trim();
    if (!excelUomName) {
      // no UOM given -> Quantity is already in the GR line's UOM
      lineQty = rawQty;
    } else {
      const uomMatch = uomList.find((u) => str(u.uom_name).trim() === excelUomName);
      if (!uomMatch) {
        errors.push('Row ' + lineNo + ': UOM "' + excelUomName + '" not found.');
      } else {
        const excelFactor = baseQtyFor(uomMatch.id);
        if (excelFactor === null) {
          errors.push(
            'Row ' + lineNo + ': UOM "' + excelUomName +
              '" is not a valid UOM for this item.');
        } else {
          // convert excel-UOM qty -> line-UOM qty
          lineQty = parseFloat(((rawQty * excelFactor) / itemUomFactor).toFixed(3));
        }
      }
    }
    if (!isNaN(lineQty)) totalReceived += lineQty;
  }

  // 1b/2. Storage Location name -> id (error if the name is ambiguous)
  const storageName = str(row["Storage Location"]).trim();
  const storageMatches = storageList.filter(
    (s) => str(s.storage_location_name).trim() === storageName);
  let storageLocationId = "";
  if (!storageName) {
    errors.push("Row " + lineNo + ": Storage Location is required.");
  } else if (storageMatches.length === 0) {
    errors.push('Row ' + lineNo + ': Storage Location "' + storageName + '" not found.');
  } else if (storageMatches.length > 1) {
    errors.push(
      'Row ' + lineNo + ': Storage Location "' + storageName +
        '" is ambiguous (matches ' + storageMatches.length + ' records in this plant).');
  } else {
    storageLocationId = storageMatches[0].id;
  }

  // 1b/2. Bin Location combine -> id, and it MUST sit under the storage above.
  const binName = str(row["Bin Location"]).trim();
  let locationId = "";
  if (!binName) {
    // Blank bin -> auto-fill the storage's default bin (once storage resolved;
    // if storage failed, its error already covers this row).
    if (storageLocationId) {
      const defBin = binDefaultList.find(
        (b) => String(b.storage_location_id) === String(storageLocationId));
      if (defBin) {
        locationId = defBin.id;
      } else {
        errors.push(
          'Row ' + lineNo + ': Bin Location is blank and Storage Location "' +
            storageName + '" has no default bin.');
      }
    }
  } else if (storageLocationId) {
    // only resolvable once the parent storage is known and unambiguous
    const binMatches = binList.filter(
      (b) =>
        str(b.bin_location_combine).trim() === binName &&
        String(b.storage_location_id) === String(storageLocationId));
    if (binMatches.length === 0) {
      errors.push(
        'Row ' + lineNo + ': Bin Location "' + binName +
          '" not found under Storage Location "' + storageName + '".');
    } else if (binMatches.length > 1) {
      errors.push(
        'Row ' + lineNo + ': Bin Location "' + binName +
          '" is ambiguous under Storage Location "' + storageName + '".');
    } else {
      locationId = binMatches[0].id;
    }
  }

  // 4. Batch handling
  let batchNo = "";
  const excelBatch = str(row["Batch Number"]).trim();
  if (!isBatchItem) {
    batchNo = ""; // non-batch item: batch column ignored
  } else if (isAutoBatch) {
    batchNo = "Auto-generated batch number";
    if (excelBatch !== "") autoBatchWarnRows.push(lineNo);
  } else {
    // manual-batch item: batch number is required
    if (excelBatch === "") {
      errors.push("Row " + lineNo + ": Batch Number is required for this manual-batch item.");
    }
    batchNo = excelBatch;
  }

  // 5. Dates (only meaningful for batch items; null for non-batch)
  let manufacturingDate = null;
  let expiredDate = null;
  if (isBatchItem) {
    const mfg = convertDate(row["Manufacturing Date"]);
    const exp = convertDate(row["Expired Date"]);
    if (mfg && mfg.error) {
      errors.push(
        'Row ' + lineNo + ': Manufacturing Date "' + mfg.raw +
          '" is not a valid date (use DD-MM-YYYY, DD/MM/YYYY or "1 Jan 2026").');
    } else {
      manufacturingDate = mfg;
    }
    if (exp && exp.error) {
      errors.push(
        'Row ' + lineNo + ': Expired Date "' + exp.raw +
          '" is not a valid date (use DD-MM-YYYY, DD/MM/YYYY or "1 Jan 2026").');
    } else {
      expiredDate = exp;
    }
    // F1: manufacturing must be on or before expiry (both zero-padded -> string compare ok)
    if (
      typeof manufacturingDate === "string" &&
      typeof expiredDate === "string" &&
      manufacturingDate > expiredDate
    ) {
      errors.push(
        "Row " + lineNo + ": Manufacturing Date must be on or before Expired Date.");
    }
  }

  tableSplit.push({
    sub_seq: lineNo,
    received_qty: isNaN(lineQty) ? 0 : lineQty,
    item_uom: itemUom,
    storage_location_id: storageLocationId,
    location_id: locationId,
    line_remark_1: str(row["Remark"]),
    line_remark_2: str(row["Remark 2"]),
    line_remark_3: str(row["Remark 3"]),
    batch_no: batchNo,
    manufacturing_date: manufacturingDate,
    expired_date: expiredDate,
  });
});

if (tableSplit.length === 0) {
  return {
    code: "400",
    message: "No rows found in the imported file.",
    table_split: "[]",
    warning: "",
  };
}

// 3b. Total quantity vs ordered qty + tolerance (mirrors GRconfirmSplitting.js)
let overReceiveTolerance = 0;
if (Array.isArray(item.table_uom_conversion)) {
  const conv = item.table_uom_conversion.find((c) => c.alt_uom_id === orderedQtyUom);
  overReceiveTolerance = (conv && conv.over_receive_tolerance) || 0;
}
const totalReceivedRounded = parseFloat(totalReceived.toFixed(3));
const maxAllowedTotalQty = parseFloat(
  ((orderedQty * (100 + overReceiveTolerance)) / 100).toFixed(3));

if (totalReceivedRounded <= 0) {
  errors.push("Total split quantity must be greater than 0.");
} else if (totalReceivedRounded + initialReceivedQty > maxAllowedTotalQty) {
  const maxAllowedQty = parseFloat((maxAllowedTotalQty - initialReceivedQty).toFixed(3));
  errors.push(
    "Total split quantity (" + totalReceivedRounded +
      ") exceeds maximum allowed quantity (" + maxAllowedQty + ") based on tolerance.");
}

if (errors.length > 0) {
  return { code: "400", message: errors.join("\n"), table_split: "[]", warning: "" };
}

let warning = "";
if (autoBatchWarnRows.length > 0) {
  warning =
    "Batch numbers were provided for row(s) " + autoBatchWarnRows.join(", ") +
    ', but this item uses auto-generated batch numbers. Those entries were ignored ' +
    'and set to "Auto-generated batch number".';
}

return {
  code: "200",
  message: "",
  table_split: JSON.stringify(tableSplit),
  warning: warning,
};
